SELECT DISTINCT "ENAME"  
FROM "EMP"  
WHERE "JOB" IN (SELECT DISTINCT "JOB" FROM "EMP" WHERE "ENAME" = 'A');

SELECT DISTINCT "EMP0"."ENAME"
FROM (SELECT "JOB" FROM "EMP" WHERE "ENAME" = 'A') AS "t0"
LEFT JOIN "EMP" AS "EMP0" ON "t0"."JOB" = "EMP0"."JOB";

/*+ NoHashJoin(t5 t6) */
SELECT t5."JOB"  
FROM (  
  SELECT DISTINCT "JOB" AS "JOB" FROM "EMP" WHERE "ENAME" = 'A'  
) AS t5  
RIGHT JOIN (  
  SELECT DISTINCT "NAME" FROM "DEPT"  
) AS t6 ON t5."JOB" = t6."NAME"  
GROUP BY t5."JOB";

SELECT e.mgr, d.mgr
FROM (SELECT DISTINCT mgr FROM emp) e
FULL OUTER JOIN (SELECT DISTINCT mgr FROM emp) d ON e.mgr = d.mgr;

